package artifacttypes

import (
	"fmt"
	"sort"
	"strings"
	"unicode"
	"unicode/utf8"
)

// Example describes a worked example for an artifact type.
type Example struct {
	Path        string
	Description string
}

// Type is the normalized artifact-type record produced by the loader.
type Type struct {
	Plugin         string
	TypeID         string
	Name           string
	Description    string
	Prefix         string
	Pattern        string
	Phase          string
	TemplatePath   string
	PromptPath     string
	Examples       []Example
	SourceMetaPath string
}

// Index is the normalized in-memory lookup index for discovered artifact types.
type Index struct {
	Types    []Type
	byKey    map[string]int
	byPrefix map[string]int
	byPlugin map[string][]int
}

// Clone returns a deep copy of the index.
func (i *Index) Clone() *Index {
	if i == nil {
		return nil
	}
	clone := &Index{Types: make([]Type, len(i.Types))}
	for idx, typ := range i.Types {
		clone.Types[idx] = cloneType(typ)
	}
	clone.rebuildLookups()
	return clone
}

// ByPlugin returns all types belonging to plugin in deterministic order.
func (i *Index) ByPlugin(plugin string) []Type {
	if i == nil || len(i.Types) == 0 {
		return nil
	}
	idxs := i.byPlugin[plugin]
	if len(idxs) == 0 {
		return nil
	}
	out := make([]Type, 0, len(idxs))
	for _, idx := range idxs {
		out = append(out, cloneType(i.Types[idx]))
	}
	return out
}

// Lookup returns the type for a plugin/typeID pair.
func (i *Index) Lookup(plugin, typeID string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byKey[keyFor(plugin, typeID)]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

// LookupPrefix returns the first type that claims prefix.
func (i *Index) LookupPrefix(prefix string) (Type, bool) {
	if i == nil {
		return Type{}, false
	}
	idx, ok := i.byPrefix[prefix]
	if !ok {
		return Type{}, false
	}
	return cloneType(i.Types[idx]), true
}

func buildIndex(types []Type) (*Index, error) {
	sorted := make([]Type, len(types))
	copy(sorted, types)
	sort.Slice(sorted, func(i, j int) bool {
		if sorted[i].Plugin != sorted[j].Plugin {
			return sorted[i].Plugin < sorted[j].Plugin
		}
		if sorted[i].TypeID != sorted[j].TypeID {
			return sorted[i].TypeID < sorted[j].TypeID
		}
		return sorted[i].SourceMetaPath < sorted[j].SourceMetaPath
	})

	idx := &Index{
		Types:    sorted,
		byKey:    make(map[string]int, len(sorted)),
		byPrefix: make(map[string]int, len(sorted)),
		byPlugin: make(map[string][]int, len(sorted)),
	}

	for i, typ := range sorted {
		if typ.Plugin == "" {
			return nil, fmt.Errorf("artifact type %q missing plugin name", typ.TypeID)
		}
		if typ.TypeID == "" {
			return nil, fmt.Errorf("artifact type in plugin %q missing type id", typ.Plugin)
		}
		key := keyFor(typ.Plugin, typ.TypeID)
		if _, exists := idx.byKey[key]; exists {
			return nil, fmt.Errorf("duplicate artifact type %s/%s", typ.Plugin, typ.TypeID)
		}
		idx.byKey[key] = i
		idx.byPlugin[typ.Plugin] = append(idx.byPlugin[typ.Plugin], i)
		if typ.Prefix != "" {
			if _, exists := idx.byPrefix[typ.Prefix]; exists {
				return nil, fmt.Errorf("duplicate artifact type prefix %q", typ.Prefix)
			}
			idx.byPrefix[typ.Prefix] = i
		}
	}
	return idx, nil
}

func (i *Index) rebuildLookups() {
	i.byKey = make(map[string]int, len(i.Types))
	i.byPrefix = make(map[string]int, len(i.Types))
	i.byPlugin = make(map[string][]int, len(i.Types))
	for idx, typ := range i.Types {
		i.byKey[keyFor(typ.Plugin, typ.TypeID)] = idx
		i.byPlugin[typ.Plugin] = append(i.byPlugin[typ.Plugin], idx)
		if typ.Prefix != "" {
			i.byPrefix[typ.Prefix] = idx
		}
	}
}

func cloneType(typ Type) Type {
	clone := typ
	if len(typ.Examples) > 0 {
		clone.Examples = append([]Example(nil), typ.Examples...)
	}
	return clone
}

func keyFor(plugin, typeID string) string {
	return plugin + "\x00" + typeID
}

func humanizeTypeID(typeID string) string {
	if typeID == "" {
		return ""
	}
	fields := strings.FieldsFunc(typeID, func(r rune) bool {
		return r == '-' || r == '_' || r == '/'
	})
	if len(fields) == 0 {
		return titleWord(typeID)
	}
	for i, field := range fields {
		fields[i] = titleWord(field)
	}
	return strings.Join(fields, " ")
}

func titleWord(s string) string {
	if s == "" {
		return ""
	}
	r, size := utf8.DecodeRuneInString(s)
	return string(unicode.ToUpper(r)) + strings.ToLower(s[size:])
}

		if walkErr != nil {
			return walkErr
		}
		if !d.IsDir() {
			return nil
		}
		rel, err := filepath.Rel(rootCanonical, p)
		if err != nil {
			return err
		}
		rel = filepath.ToSlash(rel)
		if rel == "." {
			rel = ""
		}
		if matchGlobPath(pattern, rel) {
			matches = append(matches, p)
		}
		return nil
	})
	if err != nil {
		return nil, err
	}
	return dedupeSortedPaths(matches), nil
}

func dedupeSortedPaths(paths []string) []string {
	if len(paths) == 0 {
		return nil
	}
	sort.Strings(paths)
	out := paths[:0]
	var prev string
	for i, p := range paths {
		if i == 0 || p != prev {
			out = append(out, p)
			prev = p
		}
	}
	return append([]string(nil), out...)
}

func matchGlobPath(pattern, candidate string) bool {
	pp := splitPath(pattern)
	cp := splitPath(candidate)
	return matchGlobSegments(pp, cp)
}

func matchGlobSegments(pattern, candidate []string) bool {
	if len(pattern) == 0 {
		return len(candidate) == 0
	}
	if pattern[0] == "**" {
		if len(pattern) == 1 {
			return true
		}
		for i := 0; i <= len(candidate); i++ {
			if matchGlobSegments(pattern[1:], candidate[i:]) {
				return true
			}
		}
		return false
	}
	if len(candidate) == 0 {
		return false
	}
	ok, err := path.Match(pattern[0], candidate[0])
	if err != nil || !ok {
		return false
	}
	return matchGlobSegments(pattern[1:], candidate[1:])
}

func splitPath(s string) []string {
	parts := strings.Split(filepath.ToSlash(strings.TrimSpace(s)), "/")
	out := make([]string, 0, len(parts))
	for _, part := range parts {
		if part == "" || part == "." {
			continue
		}
		out = append(out, part)
	}
	return out
}

func validateRelativePattern(pattern string) error {
	if filepath.IsAbs(pattern) {
		return fmt.Errorf("artifact_type_roots: absolute paths are not allowed: %q", pattern)
	}
	for _, part := range splitPath(pattern) {
		if part == ".." {
			return fmt.Errorf("artifact_type_roots: path escapes plugin root: %q", pattern)
		}
	}
	return nil
}

func hasGlob(s string) bool {
	return strings.ContainsAny(s, "*?[")
}

func recordSnapshot(path string) snapshot {
	info, err := os.Stat(path)
	if err != nil {
		return snapshot{path: path}
	}
	return snapshot{path: path, exists: true, modTime: info.ModTime()}
}

func canonicalPath(path string) (string, error) {
	abs, err := filepath.Abs(path)
	if err != nil {
		return "", err
	}
	resolved, err := filepath.EvalSymlinks(abs)
	if err != nil {
		if os.IsNotExist(err) {
			return abs, nil
		}
		return "", err
	}
	return resolved, nil
}

func ensureWithinRoot(rootCanonical, candidateCanonical string) error {
	rel, err := filepath.Rel(rootCanonical, candidateCanonical)
	if err != nil {
		return err
	}
	if rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return fmt.Errorf("path %s escapes plugin root %s", candidateCanonical, rootCanonical)
	}
	return nil
}

func resolveRelativeFile(rootCanonical, baseDir, rel string) (string, error) {
	trimmed := strings.TrimSpace(rel)
	if trimmed == "" {
		return "", fmt.Errorf("missing relative path")
	}
	if filepath.IsAbs(trimmed) {
		return "", fmt.Errorf("absolute paths are not allowed: %q", trimmed)
	}
	cleaned := filepath.Clean(filepath.FromSlash(trimmed))
	if cleaned == "." || cleaned == ".." || strings.HasPrefix(cleaned, ".."+string(filepath.Separator)) {
		return "", fmt.Errorf("path escapes type directory: %q", trimmed)
	}
	candidate := filepath.Join(baseDir, cleaned)
	info, err := os.Stat(candidate)
	if err != nil {
		return "", err
	}
	if info.IsDir() {
		return "", fmt.Errorf("%s is a directory", candidate)
	}
	canonical, err := canonicalPath(candidate)
	if err != nil {
		return "", err
	}
	if err := ensureWithinRoot(rootCanonical, canonical); err != nil {
		return "", err
	}
	return canonical, nil
}

func inferPhase(metaCanonical, rootCanonical string) string {
	rel, err := filepath.Rel(rootCanonical, metaCanonical)
	if err != nil {
		return ""
	}
	parts := splitPath(rel)
	for i := 0; i < len(parts); i++ {
		if parts[i] != "phases" || i+1 >= len(parts) {
			continue
		}
		phase := parts[i+1]
		if idx := strings.Index(phase, "-"); idx >= 0 && idx+1 < len(phase) {
			return phase[idx+1:]
		}
		return phase
	}
	return ""
}

func inferPrefix(pattern string) string {
	if pattern == "" {
		return ""
	}
	base := filepath.Base(pattern)
	if idx := strings.IndexAny(base, "-_."); idx > 0 {
		base = base[:idx]
	}
	if base == "" {
		return ""
	}
	if isPrefixLike(base) {
		return base
	}
	return ""
}

func isPrefixLike(s string) bool {
	if s == "" {
		return false
	}
	for _, r := range s {
		if r == '-' || r == ' ' {
			return false
		}
	}
	return strings.ToUpper(s) == s
}

func inferPrefixFromName(name string) string {
	if name == "" {
		return ""
	}
	var b strings.Builder
	for _, part := range strings.FieldsFunc(name, func(r rune) bool {
		return r == ' ' || r == '-' || r == '_' || r == '/'
	}) {
		if part == "" {
			continue
		}
		b.WriteString(strings.ToUpper(part[:1]))
	}
	if b.Len() == 0 {
		return ""
	}
	return b.String()
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if strings.TrimSpace(v) != "" {
			return strings.TrimSpace(v)
		}
	}
	return ""
}

package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

