125			idx.byPlugin[typ.Plugin] = append(idx.byPlugin[typ.Plugin], i)
126			if typ.Prefix != "" {
127				if _, exists := idx.byPrefix[typ.Prefix]; exists {
128					return nil, fmt.Errorf("duplicate artifact type prefix %q", typ.Prefix)
129				}
130				idx.byPrefix[typ.Prefix] = i
131			}
132		}
133		return idx, nil
134	}
135	
136	func (i *Index) rebuildLookups() {
137		i.byKey = make(map[string]int, len(i.Types))
138		i.byPrefix = make(map[string]int, len(i.Types))
139		i.byPlugin = make(map[string][]int, len(i.Types))
140		for idx, typ := range i.Types {
141			i.byKey[keyFor(typ.Plugin, typ.TypeID)] = idx
142			i.byPlugin[typ.Plugin] = append(i.byPlugin[typ.Plugin], idx)
143			if typ.Prefix != "" {
144				i.byPrefix[typ.Prefix] = idx
145			}
146		}
147	}
