149	func cloneType(typ Type) Type {
150		clone := typ
151		if len(typ.Examples) > 0 {
152			clone.Examples = append([]Example(nil), typ.Examples...)
153		}
154		return clone
155	}
156	
157	func keyFor(plugin, typeID string) string {
158		return plugin + "\x00" + typeID
159	}
160	
161	func humanizeTypeID(typeID string) string {
162		if typeID == "" {
163			return ""
164		}
165		fields := strings.FieldsFunc(typeID, func(r rune) bool {
166			return r == '-' || r == '_' || r == '/'
167		})
168		if len(fields) == 0 {
169			return titleWord(typeID)
170		}
171		for i, field := range fields {
172			fields[i] = titleWord(field)
173		}
174		return strings.Join(fields, " ")
175	}
176	
177	func titleWord(s string) string {
178		if s == "" {
179			return ""
180		}
181		r, size := utf8.DecodeRuneInString(s)
182		return string(unicode.ToUpper(r)) + strings.ToLower(s[size:])
183	}
